// MARK: - Models

struct Stock: Codable, Identifiable, Equatable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Double
    var previousClose: Double
    var change: Double
    var changePercent: Double
    var volume: Int64
    var lastUpdated: Date
    
    var isPositive: Bool { change >= 0 }
}

struct Position: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var quantity: Double
    var averageCost: Double
    var currentPrice: Double
    
    var marketValue: Double { quantity * currentPrice }
    var totalCost: Double { quantity * averageCost }
    var profitLoss: Double { marketValue - totalCost }
    var profitLossPercent: Double { totalCost > 0 ? (profitLoss / totalCost) * 100 : 0 }
    var isPositive: Bool { profitLoss >= 0 }
}

struct Portfolio: Codable {
    var positions: [Position]
    var cashBalance: Double
    var totalValue: Double { positions.reduce(cashBalance) { $0 + $1.marketValue } }
    var totalProfitLoss: Double { positions.reduce(0) { $0 + $1.profitLoss } }
    var dayChange: Double
    var dayChangePercent: Double
}

enum OrderType: String, Codable, CaseIterable {
    case market = "Market"
    case limit = "Limit"
    case stopLoss = "Stop Loss"
    case stopLimit = "Stop Limit"
}

enum OrderSide: String, Codable {
    case buy = "Buy"
    case sell = "Sell"
}

enum OrderStatus: String, Codable {
    case pending = "Pending"
    case filled = "Filled"
    case partiallyFilled = "Partially Filled"
    case cancelled = "Cancelled"
    case rejected = "Rejected"
    case expired = "Expired"
}

enum TimeInForce: String, Codable, CaseIterable {
    case day = "Day"
    case gtc = "GTC"
    case ioc = "IOC"
    case fok = "FOK"
}

