// MARK: - API Error

enum TradingError: LocalizedError {
    case networkError(String)
    case authenticationFailed
    case insufficientFunds
    case insufficientShares
    case invalidOrder
    case marketClosed
    case rateLimited
    case serverError(Int)
    case decodingError
    case encryptionError
    case tokenExpired
    case unknown(String)
    
    var errorDescription: String? {
        switch self {
        case .networkError(let msg): return "Network error: \(msg)"
        case .authenticationFailed: return "Authentication failed. Please log in again."
        case .insufficientFunds: return "Insufficient funds for this trade."
        case .insufficientShares: return "Insufficient shares for this sale."
        case .invalidOrder: return "Invalid order parameters."
        case .marketClosed: return "Market is currently closed."
        case .rateLimited: return "Too many requests. Please wait."
        case .serverError(let code): return "Server error (\(code)). Try again later."
        case .decodingError: return "Failed to process server response."
        case .encryptionError: return "Security error. Please restart the app."
        case .tokenExpired: return "Session expired. Please log in again."
        case .unknown(let msg): return "Unknown error: \(msg)"
        }
    }
}

// MARK: - Secure Storage

final class SecureStorage {
    static let shared = SecureStorage()
    private init() {}
    
    private let service = "com.tradingapp.secure"
    
    func save(key: String, data: Data) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func load(key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        return status == errSecSuccess ? result as? Data : nil
    }
    
    func delete(key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key
        ]
        return SecItemDelete(query as CFDictionary) == errSecSuccess
    }
    
    func saveString(_ value: String, forKey key: String) -> Bool {
        guard let data = value.data(using: .utf8) else { return false }
        return save(key: key, data: data)
    }
    
    func loadString(forKey key: String) -> String? {
        guard let data = load(key: key) else { return nil }
        return String(data: data, encoding: .utf8)
    }
}

// MARK: - Authentication Manager

final class AuthenticationManager: ObservableObject {
    static let shared = AuthenticationManager()
    
    @Published var isAuthenticated = false
    @Published var isLoading = false
    
    private let storage = SecureStorage.shared
    private let tokenKey = "auth_token"
    private let refreshTokenKey = "refresh_token"
    private let tokenExpiryKey = "token_expiry"
    
    private init() {
        checkExistingSession()
    }
    
    var authToken: String? {
        storage.loadString(forKey: tokenKey)
    }
    
    private func checkExistingSession() {
        guard let _ = storage.loadString(forKey: tokenKey),
              let expiryString = storage.loadString(forKey: tokenExpiryKey),
              let expiryInterval = TimeInterval(expiryString) else {
            isAuthenticated = false
            return
        }
        
        let expiryDate = Date(timeIntervalSince1970: expiryInterval)
        if expiryDate > Date() {
            isAuthenticated = true
        } else {
            Task { await refreshToken() }
        }
    }
    
    func login(email: String, password: String) async throws {
        await MainActor.run { isLoading = true }
        defer { Task { @MainActor in isLoading = false } }
        
        let hashedPassword = hashPassword(password)
        
        let body: [String: Any] = [
            "email": email,
            "password": hashedPassword,
            "device_id": UIDevice.current.identifierForVendor?.uuidString ?? UUID().uuidString
        ]
        
        let response = try await APIClient.shared.request(
            endpoint: "/auth/login",
            method: "POST",
            body: body,
            authenticated: false
        )
        
        guard let token = response["access_token"] as? String,
              let refreshToken = response["refresh_token"] as? String,
              let expiresIn = response["expires_in"] as? TimeInterval else {
            throw TradingError.authenticationFailed
        }
        
        let expiryDate = Date().addingTimeInterval(expiresIn)
        _ = storage.saveString(token, forKey: tokenKey)
        _ = storage.saveString(refreshToken, forKey: refreshTokenKey)
        _ = storage.saveString(String(expiryDate.timeIntervalSince1970), forKey: tokenExpiryKey)
        
        await MainActor.run { isAuthenticated = true }
    }
    
    func logout() {
        _ = storage.delete(key: tokenKey)
        _ = storage.delete(key: refreshTokenKey)
        _ = storage.delete(key: tokenExpiryKey)
        isAuthenticated = false
    }
    
    func refreshToken() async {
        guard let refreshToken = storage.loadString(forKey: refreshTokenKey) else {
            await MainActor.run { isAuthenticated = false }
            return
        }
        
        do {
            let body: [String: Any] = ["refresh_token": refreshToken]
            let response = try await APIClient.shared.request(
                endpoint: "/auth/refresh",
                method: "POST",
                body: body,
                authenticated: false
            )
            
            guard let token = response["access_token"] as? String,
                  let newRefreshToken = response["refresh_token"] as? String,
                  let expiresIn = response["expires_in"] as? TimeInterval else {
                throw TradingError.tokenExpired
            }
            
            let expiryDate = Date().addingTimeInterval(expiresIn)
            _ = storage.saveString(token, forKey: tokenKey)
            _ = storage.saveString(newRefreshToken, forKey: refreshTokenKey)
            _ = storage.saveString(String(expiryDate.timeIntervalSince1970), forKey: tokenExpiryKey)
            
            await MainActor.run { isAuthenticated = true }
        } catch {
            await MainActor.run { isAuthenticated = false }
        }
    }
    
    private func hashPassword(_ password: String) -> String {
        let data = Data(password.utf8)
        let hash = SHA256.hash(data: data)
        return hash.map { String(format: "%02x", $0) }.joined()
    }
}

// MARK: - API Client

final class APIClient {
    static let shared = APIClient()
    
    private let baseURL = "https://api.tradingplatform.com/v1"
    private let session: URLSession
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    private var rateLimitRemaining = 100
    private var rateLimitResetDate: Date?
    
    private init() {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.waitsForConnectivity = true
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        
        session = URLSession(configuration: config)
        
        decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        decoder.keyDecodingStrategy = .convertFromSnakeCase
        
        encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        encoder.keyEncodingStrategy = .convertToSnakeCase
    }
    
    func request(
        endpoint: String,
        method: String = "GET",
        body: [String: Any]? = nil,
        queryParams: [String: String]? = nil,
        authenticated: Bool = true
    ) async throws -> [String: Any] {
        if let resetDate = rateLimitResetDate, rateLimitRemaining <= 0, Date() < resetDate {
            throw TradingError.rateLimited
        }
        
        var urlComponents = URLComponents(string: baseURL + endpoint)!
        if let queryParams = queryParams {
            urlComponents.queryItems = queryParams.map { URLQueryItem(name: $0.key, value: $0.value) }
        }
        
        guard let url = urlComponents.url else {
            throw TradingError.networkError("Invalid URL")
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("TradingApp-iOS/1.0", forHTTPHeaderField: "User-Agent")
        request.setValue(UUID().uuidString, forHTTPHeaderField: "X-Request-ID")
        request.setValue(String(Date().timeIntervalSince1970), forHTTPHeaderField: "X-Timestamp")
        
        if authenticated {
            guard let token = AuthenticationManager.shared.authToken else {
                throw TradingError.authenticationFailed
            }
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
            
            if let bodyData = request.httpBody {
                let signature = generateRequestSignature(data: bodyData)
                request.setValue(signature, forHTTPHeaderField: "X-Signature")
            }
        }
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw TradingError.networkError("Invalid response")
        }
        
        if let remaining = httpResponse.value(forHTTPHeaderField: "X-RateLimit-Remaining"),
           let remainingInt = Int(remaining) {
            rateLimitRemaining = remainingInt
        }
        if let resetTime = httpResponse.value(forHTTPHeaderField: "X-RateLimit-Reset"),
           let resetInterval = TimeInterval(resetTime) {
            rateLimitResetDate = Date(timeIntervalSince1970: resetInterval)
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            guard let json = try JSONSerialization.jsonObject(with: data) as? [String: Any] else {
                throw TradingError.decodingError
            }
            return json
        case 401:
            await AuthenticationManager.shared.refreshToken()
            if AuthenticationManager.shared.isAuthenticated {
                return try await self.request(endpoint: endpoint, method: method, body: body, queryParams: queryParams, authenticated: authenticated)
            }
            throw TradingError.authenticationFailed
        case 403:
            throw TradingError.authenticationFailed
        case 429:
            throw TradingError.rateLimited
        default:
            throw TradingError.serverError(httpResponse.statusCode)
        }
    }
    
    func requestDecodable<T: Decodable>(
        endpoint: String,
        method: String = "GET",
        body: [String: Any]? = nil,
        queryParams: [String: String]? = nil,
        authenticated: Bool = true
    ) async throws -> T {
        if let resetDate = rateLimitResetDate, rateLimitRemaining <= 0, Date() < resetDate {
            throw TradingError.rateLimited
        }
        
        var urlComponents = URLComponents(string: baseURL + endpoint)!
        if let queryParams = queryParams {
            urlComponents.queryItems = queryParams.map { URLQueryItem(name: $0.key, value: $0.value) }
        }
        
        guard let url = urlComponents.url else {
            throw TradingError.networkError("Invalid URL")
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if authenticated {
            guard let token = AuthenticationManager.shared.authToken else {
                throw TradingError.authenticationFailed
            }
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
        }
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
            let statusCode = (response as? HTTPURLResponse)?.statusCode ?? -1
            throw TradingError.serverError(statusCode)
        }
        
        return try decoder.decode(T.self, from: data)
    }
    
    private func generateRequestSignature(data: Data) -> String {
        let key = SymmetricKey(size: .bits256)
        let signature = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(signature).base64EncodedString()
    }
}

// MARK: - WebSocket Manager for Real-Time Data

final class WebSocketManager: ObservableObject {
    static let shared = WebSocketManager()
    
    @Published var isConnected = false
    @Published var lastQuote: [String: MarketQuote] = [:]
    @Published var lastPrice: [String: Double] = [:]
    
    private var webSocketTask: URLSessionWebSocketTask?
    private let session = URLSession(configuration: .default)
    private var subscribedSymbols: Set<String> = []
    private var reconnectAttempts = 0
    private let maxReconnectAttempts = 5
    private var pingTimer: Timer?
    
    var priceUpdatePublisher = PassthroughSubject<(String, Double), Never>()
    
    private init() {}
    
    func connect() {
        guard let token = AuthenticationManager.shared.authToken else { return }
        
        var request = URLRequest(url: URL(string: "wss://ws.tradingplatform.com/v1/stream")!)
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        
        webSocketTask = session.webSocketTask(with: request)
        webSocketTask?.resume()
        
        isConnected = true
        reconnectAttempts = 0
        
        receiveMessage()
        startPingTimer()
        
        for symbol in subscribedSymbols {
            sendSubscribe(symbol: symbol)
        }
    }
    
    func disconnect() {
        pingTimer?.invalidate()
        pingTimer = nil
        webSocketTask?.cancel(with: .goingAway, reason: nil)
        webSocketTask = nil
        isConnected = false
    }
    
    func subscribe(to symbol: String) {
        subscribedSymbols.insert(symbol)
        if isConnected {
            sendSubscribe(symbol: symbol)
        }
    }
    
    func unsubscribe(from symbol: String) {
        subscribedSymbols.remove(symbol)
        if isConnected {
            let message: [String: Any] = [
                "action": "unsubscribe",
                "symbol": symbol
            ]
            sendJSON(message)
        }
    }
    
    private func sendSubscribe(symbol: String) {
        let message: [String: Any] = [
            "action": "subscribe",
            "symbol": symbol,
            "channels": ["quotes", "trades"]
        ]
        sendJSON(message)
    }
    
    private func sendJSON(_ dict: [String: Any]) {
        guard let data = try? JSONSerialization.data(withJSONObject: dict),
              let string = String(data: data, encoding: .utf8) else { return }
        
        webSocketTask?.send(.string(string)) { error in
            if let error = error {
                print("WebSocket send error: \(error)")
            }
        }
    }
    
    private func receiveMessage() {
        webSocketTask?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    self?.handleMessage(text)
                case .data(let data):
                    if let text = String(data: data, encoding: .utf8) {
                        self?.handleMessage(text)
                    }
                @unknown default:
                    break
                }
                self?.receiveMessage()
                
            case .failure(let error):
                print("WebSocket receive error: \(error)")
                DispatchQueue.main.async {
                    self?.isConnected = false
                }
                self?.attemptReconnect()
            }
        }
    }
    
    private func handleMessage(_ text: String) {
        guard let data = text.data(using: .utf8),
              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let type = json["type"] as? String else { return }
        
        switch type {
        case "quote":
            if let symbol = json["symbol"] as? String,
               let bid = json["bid"] as? Double,
               let ask = json["ask"] as? Double {
                let quote = MarketQuote(
                    symbol: symbol,
                    bid: bid,
                    ask: ask,
                    bidSize: json["bid_size"] as? Int ?? 0,
                    askSize: json["ask_size"] as? Int ?? 0,
                    spread: ask - bid,
                    timestamp: Date()
                )
                DispatchQueue.main.async {
                    self.lastQuote[symbol] = quote
                }
            }
            
        case "trade":
            if let symbol = json["symbol"] as? String,
               let price = json["price"] as? Double {
                DispatchQueue.main.async {
                    self.lastPrice[symbol] = price
                    self.priceUpdatePublisher.send((symbol, price))
                }
            }
            
        case "heartbeat":
            break
            
        default:
            break
        }
    }
    
    private func startPingTimer() {
        pingTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            self?.webSocketTask?.sendPing { error in
                if let error = error {
                    print("Ping error: \(error)")
                    self?.attemptReconnect()
                }
            }
        }
    }
    
    private func attemptReconnect() {
        guard reconnectAttempts < maxReconnectAttempts else {
            print("Max reconnection attempts reached")
            return
        }
        
        reconnectAttempts += 1
        let delay = Double(reconnectAttempts) * 2.0
        
        DispatchQueue.main.asyncAfter(deadline: .now() + delay) { [weak self] in
            self?.connect()
        }
    }
}

// MARK: - Trading Service

final class TradingService: ObservableObject {
    static let shared = TradingService()
    
    @Published var portfolio: Portfolio?
    @Published var orders: [TradeOrder] = []
    @Published var watchlist: [WatchlistItem] = []
    @Published var isExecutingTrade = false
    @Published var lastError: TradingError?
    
    private let api = APIClient.shared
    private var cancellables = Set<AnyCancellable>()
    
    private init() {
        WebSocketManager.shared.priceUpdatePublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] symbol, price in
                self?.updatePositionPrice(symbol: symbol, price: price)
                self?.updateWatchlistPrice(symbol: symbol, price: price)
            }
            .store(in: &cancellables)
    }
    
    // MARK: - Portfolio
    
    func fetchPortfolio() async throws {
        let portfolio: Portfolio = try await api.requestDecodable(endpoint: "/portfolio")
        await MainActor.run {
            self.portfolio = portfolio
        }
    }
    
    func fetchOrders() async throws {
        let orders: [TradeOrder] = try await api.requestDecodable(endpoint: "/orders")
        await MainActor.run {
            self.orders = orders
        }
    }
    
    func fetchWatchlist() async throws {
        let items: [WatchlistItem] = try await api.requestDecodable(endpoint: "/watchlist")
        await MainActor.run {
            self.watchlist = items
        }
    }
    
    // MARK: - Trade Execution
    
    func executeTrade(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Double,
        limitPrice: Double? = nil,
        stopPrice: Double? = nil,
        timeInForce: TimeInForce = .day
    ) async throws -> TradeConfirmation {
        await MainActor.run { isExecutingTrade = true }
        defer { Task { @MainActor in isExecutingTrade = false } }
        
        // Validation
        guard quantity > 0 else {
            throw TradingError.invalidOrder
        }
        
        if type == .limit || type == .stopLimit {
            guard let _ = limitPrice, limitPrice! > 0 else {
                throw TradingError.invalidOrder
            }
        }
        
        if type == .stopLoss || type == .stopLimit {
            guard let _ = stopPrice, stopPrice! > 0 else {
                throw TradingError.invalidOrder
            }
        }
        
        if side == .buy {
            let estimatedCost = (limitPrice ?? WebSocketManager.shared.lastPrice[symbol] ?? 0) * quantity
            guard let portfolio = portfolio, portfolio.cashBalance >= estimatedCost else {
                throw TradingError.insufficientFunds
            }
        }
        
        if side == .sell {
            guard let position = portfolio?.positions.first(where: { $0.symbol == symbol }),
                  position.quantity >= quantity else {
                throw TradingError.insufficientShares
            }
        }
        
        var body: [String: Any] = [
            "symbol": symbol,
            "side": side.rawValue.lowercased(),
            "type": type.rawValue.lowercased().replacingOccurrences(of: " ", with: "_"),
            "quantity": quantity,
            "time_in_force": timeInForce.rawValue.lowercased()
        ]
        
        if let limitPrice = limitPrice {
            body["limit_price"] = limitPrice
        }
        if let stopPrice = stopPrice {
            body["stop_price"] = stopPrice
        }
        
        let response = try await api.request(endpoint: "/orders", method: "POST", body: body)
        
        guard let orderId = response["order_id"] as? String,
              let filledPrice = response["filled_price"] as? Double,
              let total = response["total"] as? Double,
              let commission = response["commission"] as? Double else {
            throw TradingError.decodingError
        }
        
        let confirmation = TradeConfirmation(
            orderId: orderId,
            symbol: symbol,
            side: side,
            quantity: quantity,
            price: filledPrice,
            total: total,
            commission: commission,
            timestamp: Date()
        )
        
        try await fetchPortfolio()
        try await fetchOrders()
        
        return confirmation
    }
    
    func cancelOrder(_ orderId: String) async throws {
        _ = try await api.request(endpoint: "/orders/\(orderId)/cancel", method: "POST")
        try await fetchOrders()
    }
    
    // MARK: - Market Data
    
    func fetchStockQuote(symbol: String) async throws -> Stock {
        try await api.requestDecodable(endpoint: "/quotes/\(symbol)")
    }
    
    func fetchChartData(symbol: String, interval: String = "1D") async throws -> [ChartDataPoint] {
        try await api.requestDecodable(
            endpoint: "/charts/\(symbol)",
            queryParams: ["interval": interval]
        )
    }
    
    func searchStocks(query: String) async throws -> [Stock] {
        try await api.requestDecodable(
            endpoint: "/search",
            queryParams: ["q": query]
        )
    }
    
    // MARK: - Watchlist
    
    func addToWatchlist(symbol: String) async throws {
        _ = try await api.request(endpoint: "/watchlist", method: "POST", body: ["symbol": symbol])
        try await fetchWatchlist()
    }
    
    func removeFromWatchlist(symbol: String) async throws {
        _ = try await api.request(endpoint: "/watchlist/\(symbol)", method: "DELETE")
        try await fetchWatchlist()
    }
    
    // MARK: - Private Helpers
    
    private func updatePositionPrice(symbol: String, price: Double) {
        guard var portfolio = portfolio else { return }
        if let index = portfolio.positions.firstIndex(where: { $0.symbol == symbol }) {
            portfolio.positions[index].currentPrice = price
            self.portfolio = portfolio
        }
    }
    
    private func updateWatchlistPrice(symbol: String, price: Double) {
        if let index = watchlist.firstIndex(where: { $0.symbol == symbol }) {
            let previousPrice = watchlist[index].currentPrice
            watchlist[index].currentPrice = price
            watchlist[index].change = price - previousPrice
            watchlist[index].changePercent = previousPrice > 0 ? ((price - previousPrice) / previousPrice) * 100 : 0
        }
    }
}

