@MainActor
final class TradeViewModel: ObservableObject {
    @Published var stock: Stock?
    @Published var quote: MarketQuote?
    @Published var chartData: [ChartDataPoint] = []
    @Published var orderSide: OrderSide = .buy
    @Published var orderType: OrderType = .market
    @Published var quantity: String = ""
    @Published var limitPrice: String = ""
    @Published var stopPrice: String = ""
    @Published var timeInForce: TimeInForce = .day
    @Published var isLoading = false
    @Published var isExecuting = false
    @Published var errorMessage: String?
    @Published var confirmation: TradeConfirmation?
    @Published var showConfirmation = false
    @Published var selectedChartInterval = "1D"
    
    let symbol: String
    private let tradingService = TradingService.shared
    private let webSocket = WebSocketManager.shared
    private var cancellables = Set<AnyCancellable>()
    
    var estimatedTotal: Double {
        guard let qty = Double(quantity) else { return 0 }
        let price: Double
        
        switch orderType {
        case .market:
            price = stock?.currentPrice ?? 0
        case .limit, .stopLimit:
            price = Double(limitPrice) ?? stock?.currentPrice ?? 0
        case .stopLoss:
            price = Double(stopPrice) ?? stock?.currentPrice ?? 0
        }
        
        return qty * price
    }
    
    var canExecute: Bool {
        guard let qty = Double(quantity), qty > 0 else { return false }
        
        switch orderType {
        case .market:
            return true
        case .limit:
            return Double(limitPrice) != nil && Double(limitPrice)! > 0
        case .stopLoss:
            return Double(stopPrice) != nil && Double(stopPrice)! > 0
        case .stopLimit:
            return Double(limitPrice) != nil && Double(limitPrice)! > 0
                && Double(stopPrice) != nil && Double(stopPrice)! > 0
        }
    }
    
    var availableCash: Double {
        tradingService.portfolio?.cashBalance ?? 0
    }
    
    var currentPosition: Position? {
        tradingService.portfolio?.positions.first { $0.symbol == symbol }
    }
    
    init(symbol: String) {
        self.symbol = symbol
        
        webSocket.subscribe(to: symbol)
        
        webSocket.$lastQuote
            .compactMap { $0[symbol] }
            .receive(on: DispatchQueue.main)
            .assign(to: &$quote)
        
        webSocket.priceUpdatePublisher
            .filter { $0.0 == symbol }
            .receive(on: DispatchQueue.main)
            .sink { [weak self] _, price in
                self?.stock?.currentPrice = price
            }
            .store(in: &cancellables)
    }
    
    deinit {
        webSocket.unsubscribe(from: symbol)
    }
    
    func loadStockData() async {
        isLoading = true
        errorMessage = nil
        
        do {
            async let stockTask = tradingService.fetchStockQuote(symbol: symbol)
            async let chartTask = tradingService.fetchChartData(symbol: symbol, interval: selectedChartInterval)
            
            let (fetchedStock, fetchedChart) = try await (stockTask, chartTask)
            
            stock = fetchedStock
            chartData = fetchedChart
        } catch let error as TradingError {
            errorMessage = error.errorDescription
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func loadChartData(interval: String) async {
        selectedChartInterval = interval
        do {
            chartData = try await tradingService.fetchChartData(symbol: symbol, interval: interval)
        } catch {
            // Silently fail for chart updates
        }
    }
    
    func executeTrade() async {
        isExecuting = true
        errorMessage = nil
        
        do {
            let result = try await tradingService.executeTrade(
                symbol: symbol,
                side: orderSide,
                type: orderType,
                quantity: Double(quantity) ?? 0,
                limitPrice: Double(limitPrice),
                stopPrice: Double(stopPrice),
                timeInForce: timeInForce
            )
            
            confirmation = result
            showConfirmation = true
            
            // Reset form
            quantity = ""
            limitPrice = ""
            stopPrice = ""
        } catch let error as TradingError {
            errorMessage = error.errorDescription
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isExecuting = false
    }
}

@MainActor
final class WatchlistViewModel: ObservableObject {
    @Published var items: [WatchlistItem] = []
    @Published var searchResults: [Stock] = []
    @Published var searchQuery = ""
    @Published var isLoading = false
    @Published var isSearching = false
    
    private let tradingService = TradingService.shared
    private var cancellables = Set<AnyCancellable>()
    private var searchTask: Task<Void, Never>?
    
    init() {
        tradingService.$watchlist
            .receive(on: DispatchQueue.main)
            .assign(to: &$items)
        
        $searchQuery
            .debounce(for: .milliseconds(300), scheduler: DispatchQueue.main)
            .removeDuplicates()
            .sink { [weak self] query in
                self?.performSearch(query: query)
            }
            .store(in: &cancellables)
    }
    
    func loadWatchlist() async {
        isLoading = true
        do {
            try await tradingService.fetchWatchlist()
            for item in items {
                WebSocketManager.shared.subscribe(to: item.symbol)
            }
        } catch {}
        isLoading = false
    }
    
    func addSymbol(_ symbol: String) async {
        do {
            try await tradingService.addToWatchlist(symbol: symbol)
            WebSocketManager.shared.subscribe(to: symbol)
        } catch {}
    }
    
    func removeSymbol(_ symbol: String) async {
        do {
            try await tradingService.removeFromWatchlist(symbol: symbol)
            WebSocketManager.shared.unsubscribe(from: symbol)
        } catch {}
    }
    
    private func performSearch(query: String) {
        searchTask?.cancel()
        
        guard !query.isEmpty else {
            searchResults = []
            return
        }
        
        searchTask = Task {
            isSearching = true
            do {
                searchResults = try await tradingService.searchStocks(query: query)
            } catch {}
            isSearching = false
        }
    }
}

@MainActor
final class OrderHistoryViewModel: ObservableObject {
    @Published var orders: [TradeOrder] = []
    @Published var isLoading = false
    
    private let tradingService = TradingService.shared
    
    init() {
        tradingService.$orders
            .receive(on: DispatchQueue.main)
            .assign(to: &$orders)
    }
    
    func loadOrders() async {
        isLoading = true
        do {
            try await tradingService.fetchOrders()
        } catch {}
        isLoading = false
    }
    
    func cancelOrder(_ orderId: String) async {
        do {
            try await tradingService.cancelOrder(orderId)
        } catch {}
    }
    
    var pendingOrders: [TradeOrder] {
        orders.filter { $0.status == .pending || $0.status == .partiallyFilled }
    }
    
    var completedOrders: [TradeOrder] {
        orders.filter { $0.status == .filled || $0.status == .cancelled || $0.status == .rejected }
    }
}

