        view.backgroundColor = .systemBackground
        
        let stackView = UIStackView(arrangedSubviews: [
            logoImageView, titleLabel, subtitleLabel,
            UIView(), emailField, passwordField, errorLabel, loginButton, biometricButton
        ])
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.alignment = .fill
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        loginButton.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            
            logoImageView.heightAnchor.constraint(equalToConstant: 80),
            emailField.heightAnchor.constraint(equalToConstant: 50),
            passwordField.heightAnchor.constraint(equalToConstant: 50),
            loginButton.heightAnchor.constraint(equalToConstant: 50),
            biometricButton.heightAnchor.constraint(equalToConstant: 44),
            
            activityIndicator.centerXAnchor.constraint(equalTo: loginButton.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: loginButton.centerYAnchor)
        ])
    }
    
    private func setupActions() {
        loginButton.addTarget(self, action: #selector(loginTapped), for: .touchUpInside)
    }
    
    @objc private func loginTapped() {
        guard let email = emailField.text, !email.isEmpty,
              let password = passwordField.text, !password.isEmpty else {
            showError("Please enter email and password")
            return
        }
        
        setLoading(true)
        
        Task {
            do {
                try await authManager.login(email: email, password: password)
            } catch let error as TradingError {
                showError(error.errorDescription ?? "Login failed")
            } catch {
                showError(error.localizedDescription)
            }
            setLoading(false)
        }
    }
    
    private func setLoading(_ loading: Bool) {
        DispatchQueue.main.async { [weak self] in
            self?.loginButton.setTitle(loading ? "" : "Sign In", for: .normal)
            if loading {
                self?.activityIndicator.startAnimating()
            } else {
                self?.activityIndicator.stopAnimating()
            }
            self?.loginButton.isEnabled = !loading
            self?.emailField.isEnabled = !loading
            self?.passwordField.isEnabled = !loading
        }
    }
    
    private func showError(_ message: String) {
        DispatchQueue.main.async { [weak self] in
            self?.errorLabel.text = message
            self?.errorLabel.isHidden = false
        }
    }
}

