class PortfolioViewController: UIViewController {
    private let viewModel = PortfolioViewModel()
    private var cancellables = Set<AnyCancellable>()
    
    private let refreshControl = UIRefreshControl()
    
    private let scrollView: UIScrollView = {
        let sv = UIScrollView()
        sv.translatesAutoresizingMaskIntoConstraints = false
        sv.alwaysBounceVertical = true
        return sv
    }()
    
    private let contentStack: UIStackView = {
        let sv = UIStackView()
        sv.axis = .vertical
        sv.spacing = 20
        sv.translatesAutoresizingMaskIntoConstraints = false
        return sv
    }()
    
    private let totalValueLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 36, weight: .bold)
        label.textAlignment = .center
        return label
    }()
    
    private let dayChangeLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 18, weight: .medium)
        label.textAlignment = .center
        return label
    }()
    
    private let cashLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 16, weight: .regular)
        label.textColor = .secondaryLabel
        label.textAlignment = .center
        return label
    }()
    
    private let positionsTableView: UITableView = {
        let tv = UITableView(frame: .zero, style: .insetGrouped)
        tv.translatesAutoresizingMaskIntoConstraints = false
        tv.isScrollEnabled = false
        tv.register(PositionCell.self, forCellReuseIdentifier: PositionCell.identifier)
        return tv
    }()
    
    private var positionsHeightConstraint: NSLayoutConstraint?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Portfolio"
        navigationController?.navigationBar.prefersLargeTitles = true
        view.backgroundColor = .systemGroupedBackground
        
        setupUI()
        setupBindings()
        
        Task { await viewModel.loadPortfolio() }
    }
    
    private func setupUI() {
        view.addSubview(scrollView)
        scrollView.addSubview(contentStack)
        
        refreshControl.addTarget(self, action: #selector(refreshData), for: .valueChanged)
        scrollView.refreshControl = refreshControl
        
        let headerStack = UIStackView(arrangedSubviews: [totalValueLabel, dayChangeLabel, cashLabel])
        headerStack.axis = .vertical
        headerStack.spacing = 8
        headerStack.alignment = .center
        
        let headerCard = createCard(content: headerStack)
        
        let positionsHeader = UILabel()
        positionsHeader.text = "Positions"
        positionsHeader.font = .systemFont(ofSize: 22, weight: .bold)
        
        contentStack.addArrangedSubview(headerCard)
        contentStack.addArrangedSubview(positionsHeader)
        contentStack.addArrangedSubview(positionsTableView)
        
        positionsTableView.delegate = self
        positionsTableView.dataSource = self
        
        positionsHeightConstraint = positionsTableView.heightAnchor.constraint(equalToConstant: 300)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            contentStack.topAnchor.constraint(equalTo: scrollView.topAnchor, constant: 16),
            contentStack.leadingAnchor.constraint(equalTo: scrollView.leadingAnchor, constant: 16),
            contentStack.trailingAnchor.constraint(equalTo: scrollView.trailingAnchor, constant: -16),
            contentStack.bottomAnchor.constraint(equalTo: scrollView.bottomAnchor, constant: -16),
            contentStack.widthAnchor.constraint(equalTo: scrollView.widthAnchor, constant: -32),
            
            positionsHeightConstraint!
        ])
    }
    
    private func setupBindings() {
        viewModel.$portfolio
            .receive(on: DispatchQueue.main)
            .sink { [weak self] portfolio in
                self?.updateUI(with: portfolio)
            }
            .store(in: &cancellables)
        
        viewModel.$isLoading
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isLoading in
                if !isLoading {
                    self?.refreshControl.endRefreshing()
                }
            }
            .store(in: &cancellables)
    }
    
    private func updateUI(with portfolio: Portfolio?) {
        guard let portfolio = portfolio else { return }
        
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        
        totalValueLabel.text = formatter.string(from: NSNumber(value: portfolio.totalValue))
        
        let changePrefix = portfolio.dayChange >= 0 ? "+" : ""
        dayChangeLabel.text = "\(changePrefix)\(formatter.string(from: NSNumber(value: portfolio.dayChange)) ?? "") (\(String(format: "%.2f%%", portfolio.dayChangePercent)))"
        dayChangeLabel.textColor = portfolio.dayChange >= 0 ? .systemGreen : .systemRed
        
        cashLabel.text = "Cash: \(formatter.string(from: NSNumber(value: portfolio.cashBalance)) ?? "")"
        
        let rowHeight: CGFloat = 80
        positionsHeightConstraint?.constant = CGFloat(portfolio.positions.count) * rowHeight + 50
        
        positionsTableView.reloadData()
    }
    
    private func createCard(content: UIView) -> UIView {
        let card = UIView()
        card.backgroundColor = .secondarySystemGroupedBackground
        card.layer.cornerRadius = 16
        card.translatesAutoresizingMaskIntoConstraints = false
        
        card.addSubview(content)
        content.translatesAutoresizingMaskIntoConstraints = false
        
        NSLayoutConstraint.activate([
            content.topAnchor.constraint(equalTo: card.topAnchor, constant: 20),
            content.leadingAnchor.constraint(equalTo: card.leadingAnchor, constant: 16),
            content.trailingAnchor.constraint(equalTo: card.trailingAnchor, constant: -16),
            content.bottomAnchor.constraint(equalTo: card.bottomAnchor, constant: -20)
        ])
        
        return card
    }
    
    @objc private func refreshData() {
        Task { await viewModel.loadPortfolio() }
    }
}

extension PortfolioViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        viewModel.portfolio?.positions.count ?? 0
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: PositionCell.identifier, for: indexPath) as! PositionCell
        if let position = viewModel.portfolio?.positions[indexPath.row] {
            cell.configure(with: position)
        }
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        80
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        if let position = viewModel.portfolio?.positions[indexPath.row] {
            let tradeVC = TradeViewController(symbol: position.symbol)
            navigationController?.pushViewController(tradeVC, animated: true)
        }
    }
}

