        return label
    }()
    
    private let valueLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 16, weight: .semibold)
        label.textAlignment = .right
        return label
    }()
    
    private let plLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 14, weight: .medium)
        label.textAlignment = .right
        return label
    }()
    
    override init(style: UITableViewCell.CellStyle, reuseIdentifier: String?) {
        super.init(style: style, reuseIdentifier: reuseIdentifier)
        setupUI()
    }
    
    required init?(coder: NSCoder) { fatalError() }
    
    private func setupUI() {
        let leftStack = UIStackView(arrangedSubviews: [symbolLabel, nameLabel, quantityLabel])
        leftStack.axis = .vertical
        leftStack.spacing = 2
        
        let rightStack = UIStackView(arrangedSubviews: [valueLabel, plLabel])
        rightStack.axis = .vertical
        rightStack.spacing = 4
        rightStack.alignment = .trailing
        
        let mainStack = UIStackView(arrangedSubviews: [leftStack, UIView(), rightStack])
        mainStack.axis = .horizontal
        mainStack.spacing = 8
        mainStack.alignment = .center
        mainStack.translatesAutoresizingMaskIntoConstraints = false
        
        contentView.addSubview(mainStack)
        
        NSLayoutConstraint.activate([
            mainStack.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 12),
            mainStack.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            mainStack.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            mainStack.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -12)
        ])
    }
    
    func configure(with position: Position) {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        
        symbolLabel.text = position.symbol
        nameLabel.text = position.name
        quantityLabel.text = "\(String(format: "%.2f", position.quantity)) shares @ \(formatter.string(from: NSNumber(value: position.averageCost)) ?? "")"
        valueLabel.text = formatter.string(from: NSNumber(value: position.marketValue))
        
        let prefix = position.isPositive ? "+" : ""
        plLabel.text = "\(prefix)\(formatter.string(from: NSNumber(value: position.profitLoss)) ?? "") (\(String(format: "%.2f%%", position.profitLossPercent)))"
        plLabel.textColor = position.isPositive ? .systemGreen : .systemRed
    }
}

// MARK: - Watchlist View Controller

class WatchlistViewController: UIViewController {
    private let viewModel = WatchlistViewModel()
    private var cancellables = Set<AnyCancellable>()
    
    private let tableView: UITableView = {
        let tv = UITableView(frame: .zero, style: .insetGrouped)
        tv.translatesAutoresizingMaskIntoConstraints = false
        tv.register(WatchlistCell.self, forCellReuseIdentifier: WatchlistCell.identifier)
        return tv
    }()
    
    private let emptyLabel: UILabel = {
        let label = UILabel()
        label.text = "Your watchlist is empty.\nTap + to add stocks."
        label.numberOfLines = 0
        label.textAlignment = .center
        label.textColor = .secondaryLabel
        label.font = .systemFont(ofSize: 16)
        label.translatesAutoresizingMaskIntoConstraints = false
        label.isHidden = true
        return label
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Watchlist"
        navigationController?.navigationBar.prefersLargeTitles = true
        view.backgroundColor = .systemGroupedBackground
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(barButtonSystemItem: .add, target: self, action: #selector(addSymbol))
        
        setupUI()
        setupBindings()
        
        Task { await viewModel.loadWatchlist() }
    }
    
    private func setupUI() {
        view.addSubview(tableView)
        view.addSubview(emptyLabel)
        
        tableView.delegate = self
        tableView.dataSource = self
        
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor